{
  "grammar": [
    {
      "pattern": "可以 + [verb] + [object] + 嗎？",
      "structure": ["可以", "verb", "object", "嗎"],
      "explanation_en": "Use '可以' to politely ask for permission or request an action. It is a standard polite form in Taiwan.",
      "title": "Polite Request with 可以",
      "meaning": "May I...? / Can I...?",
      "when_to_use": ["When ordering at a café or shop", "When asking for permission to do something"],
      "when_not_to_use": ["When making a direct command or demand", "When speaking to close friends in casual settings"],
      "pragmatic_notes": "In Taiwan, using '可以' is very common and polite. It softens the request and shows respect.",
      "word_order_notes": "Place '可以' before the verb. The object follows the verb. End with '嗎' for a question.",
      "english_contrast": "English uses 'can I' or 'may I' at the beginning. Chinese uses '可以' before the verb.",
      "korean_contrast": "Korean uses '~을/를 해도 될까요?' structure. Chinese uses '可以' + verb + object + 嗎.",
      "negative_examples": [
        {
          "text": "可以嗎？",
          "error": "Missing verb and object; incomplete request."
        }
      ],
      "incorrect_examples": [
        {
          "text": "可以我喝水嗎？",
          "error": "Word order: '可以' must be followed directly by the verb, not the subject."
        }
      ],
      "transformation_drills": ["Change '可以喝咖啡嗎？' to '可以喝茶嗎？'", "Change '可以看菜單嗎？' to '可以拿菜單嗎？'"],
      "production_drills": ["Ask for a menu using '可以'", "Ask if you can sit here using '可以'"],
      "common_error_patterns": ["Placing subject after '可以'", "Omitting verb"],
      "repair_feedback": {
        "word_order": "Remember: 可以 + verb + object + 嗎",
        "politeness": "Using 可以 is polite; avoid direct commands.",
        "vocabulary": "Use appropriate verbs like 喝, 看, 拿, 坐"
      }
    },
    {
      "pattern": "想要 + [object]",
      "structure": ["想要", "object"],
      "explanation_en": "Use '想要' to express what you want in a polite and indirect way. It is softer than '要'.",
      "title": "Expressing Wants with 想要",
      "meaning": "I would like...",
      "when_to_use": ["When ordering food or drinks", "When stating a preference politely"],
      "when_not_to_use": ["When making a direct demand", "When urgency is needed"],
      "pragmatic_notes": "In Taiwan, '想要' is commonly used in service settings. It sounds more polite than '要'.",
      "word_order_notes": "Place '想要' before the object. No verb needed if the object is a noun.",
      "english_contrast": "English uses 'I would like' + noun. Chinese uses '想要' + noun.",
      "korean_contrast": "Korean uses '~을/를 원합니다' or '~고 싶습니다'. Chinese uses '想要' directly.",
      "negative_examples": [
        {
          "text": "想要嗎？",
          "error": "Missing object; incomplete expression."
        }
      ],
      "incorrect_examples": [
        {
          "text": "想要我咖啡嗎？",
          "error": "Incorrect word order: '想要' should be followed directly by the object, not the subject."
        }
      ],
      "transformation_drills": ["Change '想要咖啡' to '想要茶'", "Change '想要水' to '想要牛奶'"],
      "production_drills": ["Order a drink using '想要'", "Say you want a bag using '想要'"],
      "common_error_patterns": ["Adding unnecessary subject before '想要'", "Using '要' instead of '想要' in polite contexts"],
      "repair_feedback": {
        "word_order": "Use: 想要 + object",
        "politeness": "想要 is polite; avoid 要 in formal requests.",
        "vocabulary": "Use nouns like 咖啡, 茶, 水, 袋子"
      }
    },
    {
      "pattern": "不好意思，[request]",
      "structure": ["不好意思", "request"],
      "explanation_en": "Use '不好意思' as a polite softener before making a request. It shows hesitation and respect.",
      "title": "Polite Softener 不好意思",
      "meaning": "Excuse me, ... / Sorry to bother, ...",
      "when_to_use": ["When starting a request in a shop or café", "When interrupting someone"],
      "when_not_to_use": ["When apologizing for a mistake (use 對不起 instead)", "In very casual settings with friends"],
      "pragmatic_notes": "In Taiwan, '不好意思' is extremely common. It softens the request and makes it more polite.",
      "word_order_notes": "Place '不好意思' at the beginning of the sentence, followed by the request.",
      "english_contrast": "English uses 'Excuse me' or 'Sorry to bother'. Chinese uses '不好意思' similarly.",
      "korean_contrast": "Korean uses '실례합니다' or '죄송합니다'. Chinese uses '不好意思'.",
      "negative_examples": [
        {
          "text": "不好意思嗎？",
          "error": "Incorrect: '不好意思' is not a question; it is a softener."
        }
      ],
      "incorrect_examples": [
        {
          "text": "不好意思，可以嗎？",
          "error": "Incomplete request after '不好意思'; need a full request."
        }
      ],
      "transformation_drills": ["Add '不好意思' before '可以看菜單嗎？'", "Add '不好意思' before '想要一杯水'"],
      "production_drills": ["Politely ask for a menu using '不好意思'", "Politely ask for the price using '不好意思'"],
      "common_error_patterns": ["Using '不好意思' as a standalone apology", "Forgetting to add a request after '不好意思'"],
      "repair_feedback": {
        "word_order": "Use: 不好意思 + [request]",
        "politeness": "不好意思 makes any request more polite.",
        "vocabulary": "Follow with a polite request using 可以 or 想要"
      }
    }
  ]
}
